text:
{
  "formal_minutes": {
    "meeting_title": "UI Theme Package Release Readiness",
    "project_code": "PUBLIC_MEETING_SMOKE",
    "participants": ["Minjun", "Seoyeon", "Doyun", "Hara"],
    "decisions": [
      {
        "type": "confirmed_decision",
        "content": "공개 릴리스 목표는 스모크 테스트가 통과될 경우 금요일 15:00 KST로 한다."
      },
      {
        "type": "confirmed_decision",
        "content": "packageName 불일치가 발생하면 먼저 패키지 설정을 확인한다. 계약 자체가 잘못된 경우에만 스크립트를 검토한다."
      }
    ],
    "non_decisions": {
      "rejected_proposals": [
        {
          "proposal": "smoke-theme-pack.mjs가 packageName 불일치를 무시하도록 변경한다.",
          "status": "rejected"
        }
      ],
      "internal_stretch_goals": [
        {
          "proposal": "수요일 릴리스",
          "status": "internal_stretch_goal_only",
          "note": "최종 공개 릴리스 결정이 아니며, 스모크 테스트 통과 조건보다 우선하지 않는다."
        }
      ],
      "unassigned_or_tentative_items": [
        {
          "item": "README 설치 단계는 가능하면 목요일까지 검토한다.",
          "status": "no_owner_assigned"
        }
      ]
    },
    "risks": [
      {
        "risk": "잘못된 tarball 경로가 릴리스를 지연시킬 수 있다."
      },
      {
        "risk": "README 설치 단계가 오래된 상태이면 릴리스 노트가 사용자를 오도할 수 있다."
      }
    ],
    "open_questions": [
      {
        "question": "최종 릴리스 승인 권한자는 누구인가?"
      },
      {
        "question": "릴리스 노트에 내부 수요일 stretch goal을 언급해야 하는가?"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "스모크 테스트를 다시 실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "confirmed",
      "source_certainty": "confirmed_action"
    },
    {
      "owner": "Doyun",
      "task": "action_items.md에 실패 triage note를 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "confirmed",
      "source_certainty": "confirmed_action"
    },
    {
      "owner": "Hara",
      "task": "Minjun이 스모크 결과를 게시한 뒤 생성된 tarball 경로를 확인한다.",
      "due": null,
      "status": "confirmed_no_exact_deadline",
      "source_certainty": "confirmed_action_without_deadline"
    },
    {
      "owner": null,
      "task": "README 설치 단계를 가능하면 목요일까지 검토한다.",
      "due": "목요일 가능 시",
      "status": "open_unassigned",
      "source_certainty": "mentioned_but_no_owner_assigned"
    }
  ],
  "followup_note": {
    "what_to_check_next": [
      "Minjun의 금요일 10:00 KST 스모크 테스트 결과 공유 여부",
      "스모크 테스트 통과 여부에 따른 금요일 15:00 KST 공개 릴리스 가능 여부",
      "Doyun의 action_items.md 실패 triage note 작성 여부",
      "Minjun 결과 게시 후 Hara의 tarball 경로 확인 결과",
      "README 설치 단계 검토 담당자 지정 여부",
      "최종 릴리스 승인 권한자",
      "릴리스 노트에 내부 수요일 stretch goal을 언급할지 여부"
    ],
    "what_not_to_invent": [
      "고객명",
      "외부 파트너",
      "예산",
      "보안 사고",
      "프로덕션 장애",
      "법무 승인 필요 여부",
      "명시되지 않은 담당자",
      "명시되지 않은 마감일"
    ]
  },
  "non_invention_rules": {
    "customer": "고객 또는 외부 파트너는 언급되지 않았으므로 생성하지 않는다.",
    "budget": "예산 정보는 언급되지 않았으므로 생성하지 않는다.",
    "security": "보안 사고는 언급되지 않았으므로 생성하지 않는다.",
    "outage": "프로덕션 장애는 언급되지 않았으므로 생성하지 않는다.",
    "legal": "법무 승인 요구사항은 언급되지 않았으므로 생성하지 않는다.",
    "owner": "README 검토 담당자와 최종 승인 권한자는 확정되지 않았으므로 임의 배정하지 않는다.",
    "deadline": "Hara의 tarball 경로 확인에는 정확한 마감이 없으므로 임의 마감을 만들지 않는다."
  }
}
